  ('diplomatic-9e854390-moex-00506', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-110-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '依司法院大法官解釋及相關規定，關於我國獨立機關，下列敘述何者錯誤？', '["獨立機關之首長得由委員互選產生", "依中央行政機關組織基準法規定，至多僅得設置三個相當二級機關之獨立機關", "獨立機關為依法律獨立行使職權，且不受其他機關指揮監督之合議制機關", "獨立機關本身對於機關委員應有完全之人事決定權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:32+00:00", "source_pdf_sha1": "feacf0daac2e", "answer_pdf_sha1": "4af45c9595a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
