  ('diplomatic-9e854390-moex-00511', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-110-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '關於大陸地區物品勞務服務在臺灣地區從事廣告活動之規定，下列敘述何者正確？', '["可刊登廣告招攬臺灣地區人民、團體或其他機構於大陸地區投資", "婚姻媒合，不得在臺灣地區從事廣告活動或以置入性行銷方式為之", "專門職業服務，得以置入性行銷方式為之", "不動產開發及交易，得從事廣告之播映或其他促銷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:32+00:00", "source_pdf_sha1": "feacf0daac2e", "answer_pdf_sha1": "4af45c9595a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00512', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-110-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '美國政府的兩岸政策係基於「中美三個聯合公報和臺灣關係法」制訂，此「一法三公報」於中國大陸文化 大革命之「十年動亂」期間所簽訂者為：', '["上海公報", "中美建交公報", "八一七公報", "臺灣關係法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:32+00:00", "source_pdf_sha1": "feacf0daac2e", "answer_pdf_sha1": "4af45c9595a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
