  ('diplomatic-9e854390-moex-00514', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-110-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '有關中共「一帶一路」（即「新絲路經濟帶」及「21世紀海上絲路」）戰略，請選出正確敘述者：', '["此對外開放新戰略囊括大多數開發中國家，包括亞洲、非洲和拉丁美洲，不包括歐洲", "中哈原油管道是中國石油在中亞及俄羅斯地區投資建設的第一條管線，全線總長2800多公里", "為避免繞過印度等國家、節省時間成本，中國在希臘南部投資興建瓜達爾港（GwadarPort）", "2019年12月中方因美國和歐盟強力反對，已放棄中俄東線天然氣管道投產通氣投資"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:32+00:00", "source_pdf_sha1": "feacf0daac2e", "answer_pdf_sha1": "4af45c9595a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00515', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-110-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '有關歷任美國總統赴中國大陸訪問，下列敘述何者錯誤？', '["1998年6月，柯林頓（BillClinton）首次訪問中國並在北京大學對師生講話", "2008年8月，小布希（GeorgeW.Bush）出席北京奧林匹克運動會開幕典禮", "2009年11月，歐巴馬（BarackObama）訪問北京並發表「中美聯合聲明」", "2017年11月，川普（DonaldTrump）展開亞洲行並於訪中時簽署「第四公報」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:32+00:00", "source_pdf_sha1": "feacf0daac2e", "answer_pdf_sha1": "4af45c9595a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL)
